mapper.sql:
SELECT P.popup_seq, P.popup_title, P.popup_type, P.display_type, P.popup_width, P.popup_height, P.pos_left, P.pos_top, P.link_url, P.new_window_yn, P.close_btn_yn, P.all_yn, P.hide_yn, PSM.sys_id, PSM.begin_dt, PSM.end_dt, PSM.use_yn, ROW_NUMBER() OVER(ORDER BY P.popup_seq DESC) AS rsn FROM TB_POPUP_INFO P LEFT JOIN TB_POPUP_SYS_MAP PSM ON P.popup_seq = PSM.popup_seq WHERE 1=1
AND PSM.sys_id = #{sysId}
AND PSM.use_yn = #{useYn}
AND P.popup_title LIKE CONCAT('%', #{keyword}, '%')

mapper.select:
SELECT PL.* FROM (
    SELECT PO.* FROM (  ) PO
) PL
WHERE rsn > #{minSn} AND rsn <= #{maxSn}

mapper.insert:
INSERT INTO TB_POPUP_SYS_MAP (
    popup_seq, sys_id, sys_nm,
    begin_dt, end_dt, begin_time, end_time,
    use_yn, sort_order
) VALUES (
    #{popupSeq}, #{sysId}, #{sysNm},
    #{beginDt}, #{endDt}, #{beginTime}, #{endTime},
    'Y', #{sortOrder}
)
